"use client";
import { useSession } from "next-auth/react";
import {
    Wallet,
    ArrowUpRight,
    ArrowDownLeft,
    BarChart3,
    TrendingUp,
    Zap,
    Plus
} from "lucide-react";
import { useState } from "react";

export default function DashboardPage() {
    const { data: session } = useSession();

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-8 animate-in fade-in duration-700">
        
        {/* 1. HEADER SECTION */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
            <h1 className="text-3xl font-extrabold tracking-tight text-slate-900">
                Halo, {session?.user?.name?.split(' ')[0] || "User"}! 👋
            </h1>
            <p className="text-slate-500 font-medium italic">
                Mari kita petakan pengeluaranmu hari ini.
            </p>
            </div>
            <button className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-bold transition-all shadow-lg shadow-blue-200 shrink-0 w-fit">
            <Plus size={20} /> Transaksi Baru
            </button>
        </header>

        {/* 2. SUMMARY CARDS (Bento Style) */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <StatCard 
            title="Total Saldo" 
            amount="Rp 12.450.000" 
            icon={<Wallet className="text-blue-600" />} 
            color="bg-blue-50"
            />
            <StatCard 
            title="Pemasukan (Bulan ini)" 
            amount="Rp 5.200.000" 
            icon={<ArrowUpRight className="text-emerald-600" />} 
            color="bg-emerald-50"
            trend="+12%"
            />
            <StatCard 
            title="Pengeluaran (Bulan ini)" 
            amount="Rp 2.150.000" 
            icon={<ArrowDownLeft className="text-rose-600" />} 
            color="bg-rose-50"
            trend="-5%"
            />
        </div>

        {/* 3. MAIN ANALYTICS SECTION */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
            
            {/* PARETO HIGHLIGHT (The "Brain") */}
            <div className="lg:col-span-8 bg-white border border-slate-100 rounded-[2.5rem] p-8 shadow-sm hover:shadow-md transition-all">
            <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-3">
                <div className="p-3 bg-blue-600 text-white rounded-2xl shadow-lg shadow-blue-100">
                    <BarChart3 size={24} />
                </div>
                <div>
                    <h2 className="text-xl font-bold">Analisis Pola Pengeluaran</h2>
                    <p className="text-sm text-slate-400 font-medium">Prinsip 80/20 otomatis</p>
                </div>
                </div>
                <span className="px-4 py-2 bg-blue-50 text-blue-600 rounded-full text-xs font-bold uppercase tracking-wider">
                Real-time
                </span>
            </div>
            
            {/* Placeholder Chart */}
            <div className="h-64 bg-slate-50 rounded-[2rem] border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-400 gap-2">
                <TrendingUp size={48} className="opacity-20" />
                <p className="font-bold">Visualisasi Grafik Pareto</p>
                <p className="text-xs italic">(Sedang memproses data transaksi...)</p>
            </div>
            </div>

            {/* RECENT INSIGHT (Bento Sidebar) */}
            <div className="lg:col-span-4 space-y-6">
            <div className="bg-slate-900 text-white rounded-[2.5rem] p-8 relative overflow-hidden group shadow-xl">
                <div className="absolute -right-4 -top-4 w-32 h-32 bg-blue-600/20 blur-3xl rounded-full" />
                <Zap className="text-yellow-400 mb-6 group-hover:scale-110 transition-transform" size={32} />
                <h3 className="text-xl font-bold mb-2">Insight Hari Ini</h3>
                <p className="text-slate-400 text-sm leading-relaxed mb-6">
                20% pengeluaran makananmu minggu ini setara dengan 75% total budget jajanmu.
                </p>
                <button className="text-sm font-bold text-blue-400 hover:text-blue-300 transition-colors">
                Lihat Detail →
                </button>
            </div>

            <div className="bg-white border border-slate-100 rounded-[2.5rem] p-8 shadow-sm">
                <h3 className="font-bold mb-4">Dompet Aktif</h3>
                <div className="space-y-4">
                    <WalletItem name="BCA Main" balance="Rp 8.000.000" />
                    <WalletItem name="GoPay" balance="Rp 450.000" />
                    <WalletItem name="Cash" balance="Rp 200.000" />
                </div>
            </div>
            </div>

        </div>
        </div>
    );
    }

    // Sub-komponen StatCard
    function StatCard({ title, amount, icon, color, trend }: any) {
    return (
        <div className="bg-white border border-slate-100 p-8 rounded-[2.5rem] shadow-sm hover:shadow-xl transition-all group">
        <div className={`w-14 h-14 ${color} rounded-2xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform`}>
            {icon}
        </div>
        <p className="text-slate-400 text-sm font-bold uppercase tracking-wider mb-2">{title}</p>
        <div className="flex items-end justify-between">
            <h3 className="text-2xl font-black text-slate-900">{amount}</h3>
            {trend && (
            <span className={`text-xs font-bold px-2 py-1 rounded-lg ${trend.startsWith('+') ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'}`}>
                {trend}
            </span>
            )}
        </div>
        </div>
    );
}

// Sub-komponen WalletItem
function WalletItem({ name, balance }: any) {
    return (
        <div className="flex items-center justify-between p-3 rounded-2xl hover:bg-slate-50 transition-colors cursor-pointer">
        <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400">
            <Wallet size={18} />
            </div>
            <p className="font-bold text-sm text-slate-700">{name}</p>
        </div>
        <p className="text-sm font-bold text-slate-900">{balance}</p>
        </div>
    );
}